(async () => {
      try {
        const data = await getPipelineRun(runId)
        if (!cancelled) setRun(data)
      } catch (err) {
        if (!cancelled) setError(msgFromError(err))
      } finally {
        if (!cancelled) setLoading(false)
      }
    })

(async () => {
      try {
        const list = await listProjects({ signal: ac.signal })
        if (ac.signal.aborted) return
        setProjects(list)
        lastFetchedAt = Date.now()
      } catch (e) {
        if (ac.signal.aborted) return
        if (axios.isCancel(e)) return
        setLoadError(messageFromUnknown(e))
      } finally {
        if (!ac.signal.aborted) setLoading(false)
      }
    })

(async () => {
      if (!id) {
        setError('Project ID is missing from URL.')
        setLoading(false)
        return
      }
      try {
        setLoading(true)
        setError(null)
        const project = await getProject(id)
        if (!cancelled) setProjectName(project.name)
      } catch (err) {
        if (!cancelled) setError(errorMessage(err))
      } finally {
        if (!cancelled) setLoading(false)
      }
    })

(async () => {
      if (!id) {
        setError('Project ID is missing from URL.')
        setLoading(false)
        return
      }
      try {
        setLoading(true)
        setError(null)
        const project = await getProject(id)
        if (!cancelled) setCurrentProject(project)
      } catch (err) {
        if (!cancelled) setError(errorMessage(err))
      } finally {
        if (!cancelled) setLoading(false)
      }
    })

(async () => {
      try {
        const [data, planDocs] = await Promise.all([
          getTasks(currentProject.id),
          getDocuments(currentProject.id, 'PLAN'),
        ])
        if (!cancelled) {
          useTaskStore.getState().clearTaskAgentRuns()
          useTaskStore.getState().setColumns(groupedResponseToTaskColumns(data))
          setPlanApproved(planDocs.some((d) => d.status === 'approved'))
        }
      } catch {
        /* Kanban tab will surface load errors if user opens it */
      }
    })

(async () => {
      try {
        setAuditLoading(true)
        setAuditError(null)
        const page = await getAuditLogs(currentProject.id, {
          offset: auditOffset,
          limit: AUDIT_PAGE_SIZE,
        })
        if (!cancelled) setAuditPage(page)
      } catch (err) {
        if (!cancelled) {
          setAuditError(errorMessage(err))
          setAuditPage(null)
        }
      } finally {
        if (!cancelled) setAuditLoading(false)
      }
    })

